import sailpoint.tools.Util;
import sailpoint.object.Filter;
import sailpoint.object.QueryOptions;
import sailpoint.object.ManagedAttribute;
import sailpoint.object.Custom;

log.error("ename------------- " + ename);

log.error("esource------------- " + esource);

log.error("domain------------- " + domain);

if (void != ename && Util.isNotNullOrEmpty(ename) && void != esource && Util.isNotNullOrEmpty(esource)) {

String appName = null;
Filter valueFilter = null;

if (void != domain && Util.isNotNullOrEmpty(domain) ) {
Custom custom = context.getObjectByName(Custom.class, "Custom-GroupMappings");
Map domainMap = custom.get(domain);
appName = domainMap.get("appName");
valueFilter = Filter.and(Filter.eq("displayName", ename), Filter.eq("application.name", appName));
} else if ( esource.contains("Azure") ) {
azureAD = "Mexichem-Application-AzureActiveDirectory";
valueFilter = Filter.and(Filter.eq("displayName", ename), Filter.eq("application.name", azureAD));
}

if ( null != valueFilter ) {

log.error("valueFilter--- " + valueFilter.toXml());

QueryOptions qo = new QueryOptions();
qo.addFilter(valueFilter);
int count = context.countObjects(ManagedAttribute.class, qo);

log.error("count------------------ " + count);

if ( count > 0 ) {
field.setHidden(false);
return ename + " is already exist..";
} else {
return null;
}
}
}

Script.Source:
import sailpoint.tools.Util;
import sailpoint.object.Filter;
import sailpoint.object.QueryOptions;
import sailpoint.object.ManagedAttribute;
import sailpoint.object.Custom;

log.error("ename------------- " + ename);

log.error("esource------------- " + esource);

log.error("domain------------- " + domain);

if (void != ename && Util.isNotNullOrEmpty(ename) && void != esource && Util.isNotNullOrEmpty(esource)) {

String appName = null;
Filter valueFilter = null;

if (void != domain && Util.isNotNullOrEmpty(domain) ) {
Custom custom = context.getObjectByName(Custom.class, "Custom-GroupMappings");
Map domainMap = custom.get(domain);
appName = domainMap.get("appName");
valueFilter = Filter.and(Filter.eq("displayName", ename), Filter.eq("application.name", appName));
}

if ( esource.contains("Azure") ) {
valueFilter = Filter.and(Filter.eq("displayName", ename), Filter.eq("application.name", "Mexichem-Application-AzureActiveDirectory"));
}

if ( null != valueFilter ) {
log.error("valueFilter--- " + valueFilter.toXml());

QueryOptions qo = new QueryOptions();
qo.addFilter(valueFilter);

int count = context.countObjects(ManagedAttribute.class, qo);

log.error("count------------------ " + count);

if ( count > 0 ) {
StringBuilder sb = new StringBuilder();
sb.append("<p style=\"color: red; font-weight: bold;\">");
sb.append("\"").append(ename).append("\" already exists.");
sb.append("</p>");
String errorMessage = sb.toString();
field.setValue(errorMessage);
}
}
}
